import osimport cv2import numpy as npfrom typing import List, Tuple# =========================================================# 1. padding：保证能被 scale 整除# =========================================================def pad_to_divisible(        image: np.ndarray,        scale: float) -> Tuple[np.ndarray, bool]:    divisor = int(round(1 / scale))    h, w = image.shape[:2]    target_h = ((h + divisor - 1) // divisor) * divisor    target_w = ((w + divisor - 1) // divisor) * divisor    pad_h = target_h - h    pad_w = target_w - w    if pad_h == 0 and pad_w == 0:        return image, False    padded = cv2.copyMakeBorder(        image,        top=0,        bottom=pad_h,        left=0,        right=pad_w,        borderType=cv2.BORDER_CONSTANT,        value=0  # CT 黑边    )    return padded, True# =========================================================# 2. 单张图像处理# =========================================================def data_resize(        path: str,        savepath: str,        scale: float,        blur_kernel: int = 3,        blur_sigma: float = 0.8,        overwrite_hr: bool = True,        cv2interpolation = cv2.INTER_CUBIC) -> None:    image = cv2.imread(path, cv2.IMREAD_GRAYSCALE)    if image is None:        print(f"[ERROR] 读取失败：{path}")        return    original_shape = image.shape    # =========================    # padding    # =========================    image, padded = pad_to_divisible(image, scale)    if padded:        print(f"[PAD] {os.path.basename(path)} "              f"{original_shape} -> {image.shape}")        if overwrite_hr:            cv2.imwrite(                path,                image,                [cv2.IMWRITE_PNG_COMPRESSION, 0]            )            print(f"[OVERWRITE HR] {path}")    # =========================    # Gaussian blur（退化模拟）    # =========================    if blur_kernel and blur_kernel > 1:        if blur_kernel % 2 == 0:            blur_kernel += 1        image = cv2.GaussianBlur(            image,            (blur_kernel, blur_kernel),            blur_sigma        )    # =========================    # Bicubic downsample    # =========================    lr = cv2.resize(        image,        dsize=None,        fx=scale,        fy=scale,        interpolation=cv2interpolation    )    os.makedirs(savepath, exist_ok=True)    name = os.path.basename(path)    out_path = os.path.join(savepath, name)    cv2.imwrite(        out_path,        lr,        [cv2.IMWRITE_PNG_COMPRESSION, 0]    )    print(f"[LR SAVED] {name} {image.shape} -> {lr.shape}")# =========================================================# 3. batch 处理# =========================================================def batch_process(        folder: str,        savepath: str,        scale: float,        blur_kernel: int = 3,        blur_sigma: float = 0.8,        overwrite_hr: bool = True,        cv2interpolation:bool = cv2.INTER_CUBIC) -> None:    image_list: List[str] = os.listdir(folder)    total = len(image_list)    for idx, name in enumerate(image_list, start=1):        image_path = os.path.join(folder, name)        data_resize(            path=image_path,            savepath=savepath,            scale=scale,            blur_kernel=blur_kernel,            blur_sigma=blur_sigma,            overwrite_hr=overwrite_hr,cv2interpolation=cv2interpolation        )        print(f"[PROGRESS] {idx}/{total}")# =========================================================# 4. main# =========================================================if __name__ == "__main__":    folder = r"/home/liangshubo/Project/CTSR/dataset/rawdata/LDIC/LDIC_SLICE/HR_all/"    save_path = r"/home/liangshubo/Project/CTSR/dataset/rawdata/LDIC/LDIC_SLICE/HR_all/LR_blur_K5S1_x4_bicubic"    scale = 0.25  #  DOWN  4× SR    batch_process(        folder=folder,        savepath=save_path,        scale=scale,        blur_kernel=5,        blur_sigma=1.0,        overwrite_hr=True,        cv2interpolation=cv2.INTER_AREA    )    # cv2.INTER_AREA